create table wksp_arunext.mtg_card_copies (
    copy_id        number generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache
    20 noorder nocycle nokeep noscale not null enable,
    scryfall_id    varchar2(36 char) not null enable,
    location_id    number not null enable,
    finish         varchar2(20 char) default 'nonfoil' not null enable,
    condition_code varchar2(20 char),
    lang           varchar2(10 char) default 'en' not null enable,
    acquired_at    date,
    acquired_price number(12, 2),
    notes          varchar2(2000 char),
    created_at     timestamp(6) with time zone default systimestamp not null enable,
    updated_at     timestamp(6) with time zone
);

alter table wksp_arunext.mtg_card_copies
    add constraint mtg_card_copies_finish_ck
        check ( finish in ( 'nonfoil', 'foil', 'etched' ) ) enable;

alter table wksp_arunext.mtg_card_copies
    add constraint mtg_card_copies_pk primary key ( copy_id )
        using index enable;


